import React, {useEffect, useState} from 'react'
import { productAPI, cartAPI } from '../api'
import ProductCard from './ProductCard'

export default function ProductList({ onAddToCart }){
  const [products, setProducts] = useState([])
  const [categories, setCategories] = useState([])
  const [selectedCategory, setSelectedCategory] = useState(null)
  const [loading, setLoading] = useState(true)

  useEffect(()=>{
    productAPI.getProducts().then(res=>{
      const prods = res.data.results || res.data
      setProducts(prods)

      // Extract unique categories from products
      const cats = [...new Set(prods.map(p => p.category_name))].filter(Boolean).sort()
      setCategories(cats)
      setLoading(false)
    }).catch(err=>{
      console.error(err)
      setLoading(false)
    })
  },[])

  const handleAddToCart = (productId) => {
    cartAPI.addItem(productId, 1).then(()=>{
      onAddToCart()
    }).catch(err=>{
      if(err.response?.status === 401){
        alert('Please login first')
      } else {
        console.error(err)
      }
    })
  }

  const filteredProducts = selectedCategory 
    ? products.filter(p => p.category_name === selectedCategory)
    : products

  if(loading) return <div className="text-center py-16"><div className="animate-pulse text-xl text-gray-600">🛒 Loading fresh groceries...</div></div>

  return (
    <div>
      <div className="bg-gradient-to-r from-green-50 to-blue-50 rounded-lg p-6 mb-8">
        <h2 className="text-4xl font-bold text-gray-800 mb-2">🌟 Fresh Groceries</h2>
        <p className="text-gray-600">Browse our wide selection of {products.length}+ quality products</p>
      </div>

      {categories.length > 0 && (
        <div className="mb-8">
          <h3 className="text-lg font-bold text-gray-700 mb-4">Categories</h3>
          <div className="flex flex-wrap gap-3">
            <button
              onClick={() => setSelectedCategory(null)}
              className={`px-4 py-2 rounded-lg font-semibold transition ${
                selectedCategory === null
                  ? 'bg-green-600 text-white'
                  : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
              }`}
            >
              All Products
            </button>
            {categories.map(cat => (
              <button
                key={cat}
                onClick={() => setSelectedCategory(cat)}
                className={`px-4 py-2 rounded-lg font-semibold transition whitespace-nowrap ${
                  selectedCategory === cat
                    ? 'bg-green-600 text-white'
                    : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
                }`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>
      )}

      <div className="mb-4 text-gray-600">
        <span className="font-semibold">{filteredProducts.length}</span> products {selectedCategory && `in ${selectedCategory}`}
      </div>

      {filteredProducts.length === 0 ? (
        <div className="text-center py-12 bg-gray-50 rounded-lg">
          <p className="text-xl text-gray-600">No products in this category</p>
        </div>
      ) : (
        <div className="grid grid-cols-2 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
          {filteredProducts.map(p => (
            <ProductCard 
              key={p.id} 
              product={p} 
              onAddToCart={() => handleAddToCart(p.id)}
            />
          ))}
        </div>
      )}
    </div>
  )
}
